import React, { useEffect, useState } from "react";
import { Link, useNavigate } from 'react-router-dom';
import ActionButtonSection from 'src/utils/ActionButtonSection';
import alertPopUp from 'sweetalert2';
import withReactContent from 'sweetalert2-react-content';
import { deleteModalSwal, epochTogmt } from "src/utils/Common";
import { CButton } from "@coreui/react";
import DataTable from "react-data-table-component";
import { deletePosition, fetchAllPosition } from "src/components/services/PositionApi";
import { tablePositionConstant } from "./tablePositionConstant"; 
import { customStyles } from "../../utils/tableCustomStyles";
import authService from "src/auth/auth.service";

const MySwal = withReactContent(alertPopUp);

const positionList = () => {
    const [rowData, setRowData] = useState([]);
    const navigate = useNavigate();

    useEffect(() => {
        fetchPositionList();
    }, []);

    const handleDelete = async (id) => {
        const response = await deletePosition(id);
        if(response?.code === 200){
            fetchPositionList();
        }
    }

    const handleConfirmModal = (id) => {
        const handleConfirm = async () => {
            const swalval = await MySwal.fire(deleteModalSwal);
            if (swalval && swalval.value === true) {
                handleDelete(id)
            }
        };
        handleConfirm();
    };

    const fetchPositionList = async () => {
        const response = await fetchAllPosition();
        let data = [];
        if (response?.code === 200) {
            response?.results && response?.results.map((item) => {
                data.push({ name: item?.name, id: item?._id, "status": item?.status, "createTime": epochTogmt(item?.createTime) })
            });
            setRowData(data);
        }
    };

    return (<div className='row'>
        <div className="col2Large">
            <DataTable
                title="Position"
                columns={tablePositionConstant(fetchPositionList, handleConfirmModal)}
                data={rowData}
                customStyles={customStyles}
                //actions={this.actionButton()}
                pagination
                paginationPerPage={10}
                pointerOnHover
                fixedHeader
                noContextMenu
                fixedHeaderScrollHeight={"calc(100vh - 226px)"}
            />
        </div>
       {authService.getPermission("POSITION_CREATE") && <div className='col-sm-12'>
            <Link to={"/position/create"}>
                <CButton type="submit" color="primary" className="create-btn" style={{ float: "right" }}>
                    {"+ Create Position"}
                </CButton>
            </Link>
        </div>}
    </div>)
}

export default positionList;
